package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreSurroundingSpaces() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withIgnoreSurroundingSpaces();
        assertNotNull(newFormat);
        assertTrue(newFormat.getIgnoreSurroundingSpaces());
        // Also check original format is unchanged (immutable)
        assertFalse(format.getIgnoreSurroundingSpaces());
        // Check that calling withIgnoreSurroundingSpaces(true) returns equivalent result
        CSVFormat newFormat2 = format.withIgnoreSurroundingSpaces(true);
        assertEquals(newFormat, newFormat2);
    }
}
